from __future__ import annotations

from pathlib import Path

from mqt.bench.benchmarks import get_available_benchmark_names

OUTPUT_PATH = Path(__file__).parent.resolve() / "_generated_benchmarks_enum.py"


def generate_enum_file() -> None:
    names = get_available_benchmark_names()

    lines = [
        "# AUTO-GENERATED FILE. DO NOT EDIT.",
        f"# Generated by {__file__}",
        "",
        "from enum import Enum",
        "",
        "",
        "class BenchmarkName(str, Enum):",
    ]

    if not names:
        lines.append("    pass")
    else:
        for name in names:
            lines.append(f'    {name.upper()} = "{name}"')

    lines.append("")

    OUTPUT_PATH.write_text("\n".join(lines))

    print(f"Generated {OUTPUT_PATH} with {len(names)} benchmarks.")


if __name__ == "__main__":
    generate_enum_file()
